class Solution:
    def maxOperations(self, nums: List[int]) -> int:
        n = len(nums)
        if n < 2:
            return 0

        # Try all possible first operations to determine the target score
        max_ops = 0
        for i in range(1, n):
            target = nums[0] + nums[i]
            ops = 0
            j = 0
            while j + 1 < len(nums):
                if nums[j] + nums[j + 1] == target:
                    ops += 1
                    j += 2
                else:
                    break
            max_ops = max(max_ops, ops)

        return max_ops
